import { useEffect, useRef, useState, useCallback } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import { API_BASE } from '@/config/api'
import type { WSMessage, WSClientMessage, ParsedEvent } from '@/types'

const WS_URL = `ws://${window.location.host}/api/events/stream`

// Fetch log level from server once on module load
let logLevel: 'debug' | 'trace' | 'none' = 'none'
fetch(`${API_BASE}/health`)
  .then((r) => r.json())
  .then((data) => {
    const level = (data.logLevel || '').toLowerCase()
    if (level === 'trace') logLevel = 'trace'
    else if (level === 'debug') logLevel = 'debug'
  })
  .catch(() => {})

export function useWebSocket(sessionId: string | null) {
  const queryClient = useQueryClient()
  const wsRef = useRef<WebSocket | null>(null)
  const [connected, setConnected] = useState(false)
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout>>(undefined)
  const sessionIdRef = useRef(sessionId)
  sessionIdRef.current = sessionId

  const sendMessage = useCallback((msg: WSClientMessage) => {
    const ws = wsRef.current
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify(msg))
    }
  }, [])

  // Send subscribe/unsubscribe when sessionId changes
  useEffect(() => {
    if (!connected) return
    if (sessionId) {
      sendMessage({ type: 'subscribe', sessionId })
      if (logLevel === 'debug' || logLevel === 'trace') {
        console.log(`[WS] Subscribing to session ${sessionId.slice(0, 8)}`)
      }
    } else {
      sendMessage({ type: 'unsubscribe' })
      if (logLevel === 'debug' || logLevel === 'trace') {
        console.log('[WS] Unsubscribed (no session selected)')
      }
    }
  }, [sessionId, connected, sendMessage])

  const handleMessage = useCallback((msg: WSMessage) => {
    if (msg.type === 'event') {
      const event = msg.data as ParsedEvent
      const currentSessionId = sessionIdRef.current
      if (currentSessionId && event.sessionId === currentSessionId) {
        queryClient.setQueryData<ParsedEvent[]>(
          ['events', currentSessionId],
          (old) => old ? [...old, event] : [event],
        )
        if (logLevel === 'trace') {
          console.debug(`[WS] Event appended: ${event.type}/${event.subtype}${event.toolName ? ` tool:${event.toolName}` : ''}`)
        }
      }
    } else if (msg.type === 'session_update') {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
      if (logLevel === 'trace') {
        console.debug('[WS] Session update → invalidating sessions cache')
      }
    } else if (msg.type === 'project_update') {
      queryClient.invalidateQueries({ queryKey: ['projects'] })
      if (logLevel === 'trace') {
        console.debug('[WS] Project update → invalidating projects cache')
      }
    }
  }, [queryClient])

  useEffect(() => {
    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
      return
    }

    function connectWs() {
      // Guard against duplicate connections (e.g. from StrictMode reconnect races)
      if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) return

      try {
        const ws = new WebSocket(WS_URL)
        wsRef.current = ws

        ws.onopen = () => {
          setConnected(true)
          console.log('[WS] Connected')
          // Subscribe to current session on reconnect
          const sid = sessionIdRef.current
          if (sid) {
            ws.send(JSON.stringify({ type: 'subscribe', sessionId: sid }))
            if (logLevel === 'debug' || logLevel === 'trace') {
              console.log(`[WS] Subscribing to session ${sid.slice(0, 8)} (on connect)`)
            }
          }
        }

        ws.onmessage = (wsEvent) => {
          try {
            const msg: WSMessage = JSON.parse(wsEvent.data)
            handleMessage(msg)
          } catch {}
        }

        ws.onclose = () => {
          // Only handle if this is still the active connection — avoids
          // clobbering a newer connection during StrictMode remount races
          if (wsRef.current !== ws) return
          setConnected(false)
          wsRef.current = null
          console.log('[WS] Disconnected, retrying in 3s...')
          reconnectTimeoutRef.current = setTimeout(connectWs, 3000)
        }

        ws.onerror = () => {
          ws.close()
        }
      } catch {
        reconnectTimeoutRef.current = setTimeout(connectWs, 5000)
      }
    }

    connectWs()

    return () => {
      clearTimeout(reconnectTimeoutRef.current)
      wsRef.current?.close()
      wsRef.current = null
    }
  }, [handleMessage])

  return { connected }
}

import { useMemo } from 'react'
import { useQuery, useQueryClient } from '@tanstack/react-query'
import { api } from '@/lib/api-client'
import type { Agent, ServerAgent, ParsedEvent } from '@/types'

// Module-level dedup — shared across all useAgents instances so multiple
// components (event-stream, combobox, timeline) don't each fire a fetch
// for the same unknown agent.
const pendingFetches = new Set<string>()

/**
 * Derives full Agent objects from server metadata + events.
 * Status, eventCount, and timing are computed from events.
 * Detects unknown agents and fetches their metadata on demand.
 */
export function useAgents(sessionId: string | null, events: ParsedEvent[] | undefined): Agent[] {
  const queryClient = useQueryClient()

  const { data: serverAgents } = useQuery({
    queryKey: ['agents', sessionId],
    queryFn: () => api.getAgents(sessionId!),
    enabled: !!sessionId,
  })

  return useMemo(() => {
    if (!events) return []

    // Build per-agent stats from events
    const agentStats = new Map<string, {
      eventCount: number
      firstEventAt: number
      lastEventAt: number
      lastStoppedAt: number // timestamp of last stop signal, 0 if never
    }>()

    const stopSubtypes = new Set(['Stop', 'SessionEnd', 'stop_hook_summary'])

    for (const e of events) {
      let stats = agentStats.get(e.agentId)
      if (!stats) {
        stats = { eventCount: 0, firstEventAt: e.timestamp, lastEventAt: e.timestamp, lastStoppedAt: 0 }
        agentStats.set(e.agentId, stats)
      }
      stats.eventCount++
      if (e.timestamp < stats.firstEventAt) stats.firstEventAt = e.timestamp
      if (e.timestamp > stats.lastEventAt) stats.lastEventAt = e.timestamp

      // Stop signals for this agent's own events
      if (stopSubtypes.has(e.subtype ?? '')) {
        stats.lastStoppedAt = Math.max(stats.lastStoppedAt, e.timestamp)
      }

      // SubagentStop targets the agent ID in the payload, not the event's agentId
      if (e.subtype === 'SubagentStop') {
        const targetId = (e.payload as any)?.agent_id
        if (targetId) {
          const targetStats = agentStats.get(targetId)
          if (targetStats) {
            targetStats.lastStoppedAt = Math.max(targetStats.lastStoppedAt, e.timestamp)
          }
        }
      }
    }

    // Server metadata lookup
    const serverMap = new Map<string, ServerAgent>()
    serverAgents?.forEach((a) => serverMap.set(a.id, a))

    // Merge: for every agent seen in events, create a full Agent
    const result: Agent[] = []
    for (const [agentId, stats] of agentStats) {
      const server = serverMap.get(agentId)

      // Fetch metadata for agents we haven't seen from the server yet
      if (!server && !pendingFetches.has(agentId)) {
        pendingFetches.add(agentId)
        api.getAgent(agentId).then((agent) => {
          queryClient.setQueryData<ServerAgent[]>(
            ['agents', sessionId],
            (old) => {
              if (!old) return [agent]
              if (old.some((a) => a.id === agent.id)) {
                return old.map((a) => a.id === agent.id ? agent : a)
              }
              return [...old, agent]
            },
          )
        }).catch(() => {})
      }

      result.push({
        id: agentId,
        sessionId: sessionId || '',
        parentAgentId: server?.parentAgentId ?? null,
        description: server?.description ?? null,
        name: server?.name ?? null,
        agentType: server?.agentType ?? null,
        // Agent is stopped if the last stop signal came after or at the last activity
        status: stats.lastStoppedAt >= stats.lastEventAt ? 'stopped' : 'active',
        eventCount: stats.eventCount,
        firstEventAt: stats.firstEventAt,
        lastEventAt: stats.lastEventAt,
      })
    }

    return result
  }, [events, serverAgents, sessionId, queryClient])
}

