import { useUIStore } from '@/stores/ui-store'

/**
 * Returns the current "now" timestamp for timeline calculations.
 * When timeOverride is set (time travel mode), returns that instead of Date.now().
 */
export function getNow(): number {
  return useUIStore.getState().timeOverride ?? Date.now()
}

import { useRef, useMemo, useCallback } from 'react'
import { cn } from '@/lib/utils'
import { getNow } from '@/lib/get-now'
import { getEventIcon, getEventColor } from '@/config/event-icons'
import { getEventSummary } from '@/lib/event-summary'
import { useUIStore } from '@/stores/ui-store'
import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip'
import { AgentLabel } from '@/components/shared/agent-label'
import type { Agent, ParsedEvent } from '@/types'

// Renders event dots with CSS-driven drift animation.
// Each dot mounts at its current position and CSS-transitions to -5% (off-screen).
// On scale change, all dots are unmounted and remounted via a key change.
function DotContainer({
  events,
  rangeMs,
  generation,
  timeFrozen,
  setScrollToEventId,
}: {
  events: ParsedEvent[]
  rangeMs: number
  generation: number
  timeFrozen: boolean
  setScrollToEventId: (id: number | null) => void
}) {
  return (
    <>
      {events.map((event) => {
        const age = getNow() - event.timestamp
        const position = 100 - (age / rangeMs) * 100
        if (position < -10 || position > 100) return null

        const remainingMs = Math.max(0, rangeMs - age)
        const Icon = getEventIcon(event.subtype, event.toolName)
        const { dotColor, customHex } = getEventColor(event.subtype, event.toolName)
        const summary = getEventSummary(event)

        return (
          <Tooltip key={`${event.id}-${generation}`}>
            <TooltipTrigger asChild>
              <button
                className="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 cursor-pointer hover:scale-125"
                style={{ left: `${position}%` }}
                ref={timeFrozen ? undefined : (el) => {
                  if (!el) return
                  // Start drift: set position without transition, then animate to off-screen
                  requestAnimationFrame(() => {
                    el.style.transition = `left ${remainingMs}ms linear`
                    el.style.left = '-5%'
                  })
                }}
                onClick={() => setScrollToEventId(event.id)}
              >
                <span className={cn('flex items-center justify-center h-5 w-5 rounded-full', !customHex && dotColor)} style={customHex ? { backgroundColor: customHex } : undefined}>
                  <Icon className="h-3 w-3 text-white" />
                </span>
              </button>
            </TooltipTrigger>
            <TooltipContent side="top" className="text-xs max-w-64">
              <div className="font-medium">{tooltipLabel(event)}</div>
              {summary && <div className="opacity-80 truncate">{summary}</div>}
            </TooltipContent>
          </Tooltip>
        )
      })}
    </>
  )
}

interface AgentLaneProps {
  agent: Agent
  parentAgent?: Agent | null
  events: ParsedEvent[]
  allEvents: ParsedEvent[]
  isSubagent: boolean
  color: string
}

// Friendly label for tooltips
function tooltipLabel(event: ParsedEvent): string {
  if (event.subtype === 'PreToolUse' || event.subtype === 'PostToolUse') {
    return event.toolName || 'Tool'
  }
  const map: Record<string, string> = {
    UserPromptSubmit: 'Prompt',
    Stop: 'Stop',
    SessionStart: 'Session Start',
  }
  return map[event.subtype || ''] || event.subtype || event.type
}

export function AgentLane({ agent, parentAgent, events, allEvents, isSubagent, color }: AgentLaneProps) {
  const agentId = agent.id
  const { timeRange, setScrollToEventId, iconCustomizationVersion, timeOverride } = useUIStore()

  const rangeMs = useMemo(() => {
    const ranges = { '1m': 60_000, '5m': 300_000, '10m': 600_000, '60m': 3_600_000 }
    return ranges[timeRange]
  }, [timeRange])

  // Increment generation on scale change to force all dots to remount
  const generationRef = useRef(0)
  const prevRangeRef = useRef(rangeMs)
  if (prevRangeRef.current !== rangeMs) {
    prevRangeRef.current = rangeMs
    generationRef.current++
  }

  // Also remount dots when icon customizations change
  const prevCustomVersionRef = useRef(iconCustomizationVersion)
  if (prevCustomVersionRef.current !== iconCustomizationVersion) {
    prevCustomVersionRef.current = iconCustomizationVersion
    generationRef.current++
  }

  // Remount dots when time override changes (time travel)
  const prevTimeOverrideRef = useRef(timeOverride)
  if (prevTimeOverrideRef.current !== timeOverride) {
    prevTimeOverrideRef.current = timeOverride
    generationRef.current++
  }

  const generation = generationRef.current

  const visibleEvents = useMemo(
    () => events.filter((e) => getNow() - e.timestamp < rangeMs),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [events, rangeMs, timeOverride],
  )

  // Tick marks based on time range
  const ticks = useMemo(() => {
    const rangeSec = rangeMs / 1000
    const count = { '1m': 6, '5m': 5, '10m': 5, '60m': 6 }[timeRange]
    const stepSec = rangeSec / count
    const result: { pct: number; label: string }[] = []
    for (let i = 0; i <= count; i++) {
      const sec = i * stepSec
      const pct = 100 - (sec / rangeSec) * 100
      let label: string
      if (i === 0) label = 'now'
      else if (sec < 60) label = `${sec}s`
      else label = `${Math.round(sec / 60)}m`
      result.push({ pct, label })
    }
    return result
  }, [timeRange, rangeMs])

  const handleAgentNameClick = useCallback(() => {
    // Find the first event from this agent across all events (sorted by id ascending)
    const agentEvents = allEvents.filter((e) => e.agentId === agentId)
    if (agentEvents.length > 0) {
      // Events are ordered by id; the first one is the earliest
      const first = agentEvents.reduce((a, b) => (a.id < b.id ? a : b))
      setScrollToEventId(first.id)
    }
  }, [allEvents, agentId, setScrollToEventId])

  return (
    <div className="flex items-center h-8 border-b border-border/30">
      <button
        className={cn('w-40 shrink-0 text-[10px] truncate px-2 text-left cursor-pointer hover:underline', color, isSubagent ? 'opacity-80 dark:opacity-50' : 'opacity-100 dark:opacity-70')}
        onClick={handleAgentNameClick}
      >
        {isSubagent ? '↳ ' : ''}
        <AgentLabel agent={agent} parentAgent={parentAgent} />
      </button>

      <div className="flex-1 relative h-full overflow-hidden">
        <DotContainer
          events={visibleEvents}
          rangeMs={rangeMs}
          generation={generation}
          timeFrozen={timeOverride !== null}
          setScrollToEventId={setScrollToEventId}
        />

        {/* Time tick marks */}
        {ticks.map(({ pct, label }) => (
          <div
            key={label}
            className="absolute top-0 bottom-0 flex flex-col items-center"
            style={{ left: `${pct}%` }}
          >
            <div className="w-px h-full border-l border-border/20" />
            <div className="absolute bottom-0 text-[7px] text-muted-foreground/70 dark:text-muted-foreground/40 -translate-x-1/2 leading-none">
              {label}
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}

import { useCallback, useRef, useMemo, useState, useEffect } from 'react'
import { useUIStore } from '@/stores/ui-store'
import { useEvents } from '@/hooks/use-events'
import { useAgents } from '@/hooks/use-agents'
import { useSessions } from '@/hooks/use-sessions'
import { buildAgentColorMap, getAgentColorById } from '@/lib/agent-utils'
import { AgentLane } from './agent-lane'
import { Button } from '@/components/ui/button'
import { TooltipProvider } from '@/components/ui/tooltip'
import type { Agent, ParsedEvent } from '@/types'

export function ActivityTimeline() {
  const {
    selectedProjectId,
    selectedSessionId,
    selectedAgentIds,
    timelineHeight,
    timeRange,
    timeOverride,
    setTimelineHeight,
    setTimeRange,
    setTimeOverride,
  } = useUIStore()

  const { data: sessions } = useSessions(selectedProjectId)
  const effectiveSessionId = selectedSessionId || sessions?.[0]?.id || null
  const { data: events } = useEvents(effectiveSessionId)
  const agents = useAgents(effectiveSessionId, events)
  const resizing = useRef(false)
  const startY = useRef(0)
  const startHeight = useRef(0)

  // Periodic cleanup tick: forces re-render so expired dots are removed from DOM.
  // Also triggers when new events arrive.
  const [, setCleanupTick] = useState(0)
  useEffect(() => {
    const id = setInterval(() => setCleanupTick((t) => t + 1), 5_000)
    return () => clearInterval(id)
  }, [])
  const eventsLength = events?.length ?? 0
  useEffect(() => {
    setCleanupTick((t) => t + 1)
  }, [eventsLength])

  const flatAgents = useMemo(() => {
    const mainAgents: { agent: Agent; isSubagent: boolean }[] = []
    const nonMainAgents: { agent: Agent; isSubagent: boolean }[] = []
    for (const a of agents) {
      if (selectedAgentIds.length > 0 && !selectedAgentIds.includes(a.id)) continue
      if (!a.parentAgentId) {
        mainAgents.push({ agent: a, isSubagent: false })
      } else {
        nonMainAgents.push({ agent: a, isSubagent: true })
      }
    }
    // Reverse non-main agents so newest appear right after Main
    nonMainAgents.reverse()
    return [...mainAgents, ...nonMainAgents]
  }, [agents, selectedAgentIds])

  const agentColorMap = useMemo(() => buildAgentColorMap(agents), [agents])

  const eventsByAgent = useMemo(() => {
    const map = new Map<string, ParsedEvent[]>()
    events?.forEach((e) => {
      const list = map.get(e.agentId) || []
      list.push(e)
      map.set(e.agentId, list)
    })
    return map
  }, [events])

  const containerRef = useRef<HTMLDivElement>(null)

  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault()
      resizing.current = true
      startY.current = e.clientY
      startHeight.current = timelineHeight

      const onMouseMove = (e: MouseEvent) => {
        if (!resizing.current) return
        const delta = e.clientY - startY.current
        const newHeight = Math.max(60, Math.min(400, startHeight.current + delta))
        // Update DOM directly during drag to avoid React re-renders
        if (containerRef.current) {
          containerRef.current.style.height = `${newHeight}px`
          const scrollArea = containerRef.current.querySelector('[data-scroll-area]') as HTMLElement
          if (scrollArea) scrollArea.style.height = `${newHeight - 32}px`
        }
      }

      const onMouseUp = (e: MouseEvent) => {
        resizing.current = false
        const delta = e.clientY - startY.current
        const finalHeight = Math.max(60, Math.min(400, startHeight.current + delta))
        // Commit final height to React state
        setTimelineHeight(finalHeight)
        document.removeEventListener('mousemove', onMouseMove)
        document.removeEventListener('mouseup', onMouseUp)
      }

      document.addEventListener('mousemove', onMouseMove)
      document.addEventListener('mouseup', onMouseUp)
    },
    [timelineHeight, setTimelineHeight],
  )

  if (!effectiveSessionId) return null

  const ranges: Array<'1m' | '5m' | '10m' | '60m'> = ['1m', '5m', '10m', '60m']

  // For "time travel": jump to the latest event's timestamp
  const latestEventTimestamp = useMemo(() => {
    if (!events || events.length === 0) return null
    return Math.max(...events.map((e) => e.timestamp))
  }, [events])

  const handleTimeTravel = useCallback(() => {
    if (timeOverride) {
      setTimeOverride(null)
    } else if (latestEventTimestamp) {
      setTimeOverride(latestEventTimestamp)
    }
  }, [timeOverride, latestEventTimestamp, setTimeOverride])

  const timeTravelLabel = useMemo(() => {
    if (!timeOverride) return null
    const d = new Date(timeOverride)
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })
  }, [timeOverride])

  return (
    <TooltipProvider>
      <div ref={containerRef} className="border-b border-border" style={{ height: timelineHeight }}>
        <div className="flex items-center justify-between px-3 py-1 border-b border-border/50">
          <span className="text-xs text-muted-foreground font-medium">
            Activity
            {timeTravelLabel && (
              <span className="ml-2 text-amber-500">@ {timeTravelLabel}</span>
            )}
          </span>
          <div className="flex gap-1">
            <Button
              variant={timeOverride ? 'default' : 'ghost'}
              size="sm"
              className={`h-5 px-2 text-[10px] ${timeOverride ? 'bg-amber-600 hover:bg-amber-700 text-white' : ''}`}
              onClick={handleTimeTravel}
              title={timeOverride ? 'Return to live' : 'Jump to latest event (time travel)'}
            >
              {timeOverride ? 'Live' : 'Rewind'}
            </Button>
            <span className="w-px bg-border/50" />
            {ranges.map((r) => (
              <Button
                key={r}
                variant={timeRange === r ? 'default' : 'ghost'}
                size="sm"
                className="h-5 px-2 text-[10px]"
                onClick={() => setTimeRange(r)}
              >
                {r}
              </Button>
            ))}
          </div>
        </div>

        <div data-scroll-area className="overflow-y-auto" style={{ height: timelineHeight - 32 }}>
          {flatAgents.map(({ agent, isSubagent }, idx) => (
            <AgentLane
              key={agent.id}
              agent={agent}
              parentAgent={agent.parentAgentId ? agents.find((a) => a.id === agent.parentAgentId) : null}
              events={eventsByAgent.get(agent.id) || []}
              allEvents={events || []}
              isSubagent={isSubagent}
              color={getAgentColorById(agent.id, agentColorMap).textOnly}
            />
          ))}
          {flatAgents.length === 0 && (
            <div className="flex items-center justify-center h-full text-xs text-muted-foreground">
              No agent activity
            </div>
          )}
        </div>

        <div
          className="h-1 cursor-row-resize hover:bg-primary/20 active:bg-primary/30"
          onMouseDown={handleMouseDown}
        />
      </div>
    </TooltipProvider>
  )
}

